import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../styles/Home.css';

function Home() {
  const [activeTab, setActiveTab] = useState('post-job');
  const [jobs, setJobs] = useState([]);
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    fetchJobs();
  }, []);

  const fetchJobs = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/jobs');
      if (response.data.success) {
        setJobs(response.data.data);
      }
    } catch (error) {
      console.error('Error fetching jobs:', error);
    }
  };

  return (
    <div className="home-container">
      <div className="welcome-section">
        <h2>Welcome to AI-Powered Resume Shortlisting</h2>
        <p>Automate your recruitment process with intelligent resume screening</p>
      </div>

      <div className="tabs">
        <button 
          className={`tab ${activeTab === 'post-job' ? 'active' : ''}`}
          onClick={() => setActiveTab('post-job')}
        >
          📝 Post Job
        </button>
        <button 
          className={`tab ${activeTab === 'upload-resume' ? 'active' : ''}`}
          onClick={() => setActiveTab('upload-resume')}
        >
          📄 Upload Resume
        </button>
        <button 
          className={`tab ${activeTab === 'dashboard' ? 'active' : ''}`}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
      </div>

      <div className="tab-content">
        {activeTab === 'post-job' && <JobPostForm onJobCreated={fetchJobs} setMessage={setMessage} />}
        {activeTab === 'upload-resume' && <ResumeUploadForm jobs={jobs} setMessage={setMessage} />}
        {activeTab === 'dashboard' && <Dashboard jobs={jobs} />}
      </div>

      {message.text && (
        <div className={`message ${message.type}`}>
          {message.text}
        </div>
      )}
    </div>
  );
}

// Simple inline components for now
function JobPostForm({ onJobCreated, setMessage }) {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    requiredSkills: '',
    company: '',
    location: ''
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const skills = formData.requiredSkills.split(',').map(s => s.trim()).filter(s => s);
      const response = await axios.post('http://localhost:5000/api/jobs', {
        ...formData,
        requiredSkills: skills
      });
      
      if (response.data.success) {
        setMessage({ type: 'success', text: 'Job posted successfully!' });
        setFormData({ title: '', description: '', requiredSkills: '', company: '', location: '' });
        onJobCreated();
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Error posting job' });
    }
  };

  return (
    <form onSubmit={handleSubmit} className="form">
      <input
        type="text"
        placeholder="Job Title *"
        value={formData.title}
        onChange={(e) => setFormData({...formData, title: e.target.value})}
        required
      />
      <input
        type="text"
        placeholder="Company"
        value={formData.company}
        onChange={(e) => setFormData({...formData, company: e.target.value})}
      />
      <textarea
        placeholder="Job Description *"
        value={formData.description}
        onChange={(e) => setFormData({...formData, description: e.target.value})}
        required
        rows="6"
      />
      <input
        type="text"
        placeholder="Required Skills (comma-separated)"
        value={formData.requiredSkills}
        onChange={(e) => setFormData({...formData, requiredSkills: e.target.value})}
      />
      <button type="submit">📝 Post Job</button>
    </form>
  );
}

function ResumeUploadForm({ jobs, setMessage }) {
  const [formData, setFormData] = useState({
    candidateName: '',
    email: '',
    phone: '',
    jobId: ''
  });
  const [file, setFile] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setMessage({ type: 'error', text: 'Please select a resume file' });
      return;
    }

    const uploadData = new FormData();
    uploadData.append('resume', file);
    Object.keys(formData).forEach(key => uploadData.append(key, formData[key]));

    try {
      const response = await axios.post('http://localhost:5000/api/resumes/upload', uploadData);
      if (response.data.success) {
        setMessage({ type: 'success', text: 'Resume uploaded successfully!' });
        setFormData({ candidateName: '', email: '', phone: '', jobId: '' });
        setFile(null);
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Error uploading resume' });
    }
  };

  return (
    <form onSubmit={handleSubmit} className="form">
      <input
        type="text"
        placeholder="Full Name *"
        value={formData.candidateName}
        onChange={(e) => setFormData({...formData, candidateName: e.target.value})}
        required
      />
      <input
        type="email"
        placeholder="Email *"
        value={formData.email}
        onChange={(e) => setFormData({...formData, email: e.target.value})}
        required
      />
      <input
        type="tel"
        placeholder="Phone"
        value={formData.phone}
        onChange={(e) => setFormData({...formData, phone: e.target.value})}
      />
      <select
        value={formData.jobId}
        onChange={(e) => setFormData({...formData, jobId: e.target.value})}
        required
      >
        <option value="">-- Select a Job --</option>
        {jobs.map(job => (
          <option key={job._id} value={job._id}>
            {job.title} - {job.company || 'Company'}
          </option>
        ))}
      </select>
      <input
        type="file"
        accept=".pdf,.docx"
        onChange={(e) => setFile(e.target.files[0])}
        required
      />
      <button type="submit">📤 Upload Resume</button>
    </form>
  );
}

function Dashboard({ jobs }) {
  const [selectedJobId, setSelectedJobId] = useState('');
  const [rankings, setRankings] = useState([]);
  const [loading, setLoading] = useState(false);

  const generateRankings = async () => {
    if (!selectedJobId) return;
    setLoading(true);
    try {
      const response = await axios.post(`http://localhost:5000/api/rankings/generate/${selectedJobId}`);
      if (response.data.success) {
        fetchRankings();
      }
    } catch (error) {
      console.error('Error generating rankings:', error);
    }
    setLoading(false);
  };

  const fetchRankings = async () => {
    if (!selectedJobId) return;
    try {
      const response = await axios.get(`http://localhost:5000/api/rankings/job/${selectedJobId}`);
      if (response.data.success) {
        setRankings(response.data.data);
      }
    } catch (error) {
      console.error('Error fetching rankings:', error);
    }
  };

  useEffect(() => {
    if (selectedJobId) fetchRankings();
  }, [selectedJobId]);

  return (
    <div className="dashboard">
      <div className="controls">
        <select value={selectedJobId} onChange={(e) => setSelectedJobId(e.target.value)}>
          <option value="">-- Select a Job --</option>
          {jobs.map(job => (
            <option key={job._id} value={job._id}>{job.title}</option>
          ))}
        </select>
        <button onClick={generateRankings} disabled={!selectedJobId || loading}>
          {loading ? '⏳ Generating...' : '🔄 Generate Rankings'}
        </button>
      </div>

      {rankings.length > 0 && (
        <div className="rankings-list">
          <h3>Top {rankings.length} Candidates</h3>
          {rankings.map((ranking) => (
            <div key={ranking._id} className="ranking-card">
              <div className="rank-badge">#{ranking.rank}</div>
              <div className="candidate-info">
                <h4>{ranking.resumeId?.candidateName || 'Unknown'}</h4>
                <p>{ranking.resumeId?.email || 'No email'}</p>
                <div className="match-score">{ranking.matchPercentage.toFixed(1)}%</div>
              </div>
              {ranking.matchedSkills?.length > 0 && (
                <div className="skills">
                  <strong>✅ Matched:</strong> {ranking.matchedSkills.join(', ')}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default Home;
